.darma-loader-darma-custom-543 {color: var(--loader-color, #059669);
   width: 60px;
   aspect-ratio: 1;
   --c:no-repeat linear-gradient(var(--loader-color, #059669) 0 0);
   background: var(--c),var(--c),var(--c),var(--c);
   animation: darma-loader-darma-custom-543-l9-1 1.5s infinite, darma-loader-darma-custom-543-l9-2 1.5s infinite;
}
@keyframes darma-loader-darma-custom-543-l9-1  {
  0% {background-size: 0 4px,4px 0 }
25% {background-size: 40px 4px,4px 0 }
45%, 55% {background-size: 40px 4px,4px 42px}
75% {background-size: 0 4px,4px 42px}
100% {background-size: 0 4px,4px 0 }
}
@keyframes darma-loader-darma-custom-543-l9-2  {
  0%,49.9% {background-position: 0 38px ,18px 18px,100% 18px,right 18px bottom 18px}
50%,100% {background-position: right 20px bottom 18px,18px 100%,20px 18px,right 18px top 0 }
}

